import numpy as np

def distance(pos1, pos2):
    return np.linalg.norm(pos1 - pos2)

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    best_score = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        distance_to_customer = distance(cur_truck_pos, customer_pos)
        time_to_customer = distance_to_customer / truck_speed

        if current_time + time_to_customer > time_windows[i][1]:
            continue

        if current_time + time_to_customer < time_windows[i][0]:
            wait_time = time_windows[i][0] - current_time - time_to_customer
        else:
            wait_time = 0

        score = distance_to_customer + wait_time

        if score < best_score:
            best_score = score
            best_node = i

    return best_node
